const items = $input.all();

// If DataTable returned 0 rows, create an empty item so the IF node can route to false-branch
if (items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
  return [{
    json: {
      name: null,
      profile: null,
      session_id: null,
      persona_id: null,
      slack_slot: null,
      _noPersonaFound: true
    }
  }];
}

return items;

// Merge all downloaded file binaries + add binaryKeys for Anthropic node
const triggerData = $('Execute Workflow Trigger').first().json;
const personaData = $('Ensure Item').first().json;
const downloadedItems = $input.all();

const mergedBinary = {};
const keys = [];
let fileCount = 0;

for (const item of downloadedItems) {
  if (item.binary) {
    for (const [key, value] of Object.entries(item.binary)) {
      const newKey = `file_${fileCount}`;
      mergedBinary[newKey] = value;
      keys.push(newKey);
      fileCount++;
    }
  }
}

return [{
  json: {
    ...personaData,
    sessionId: triggerData.sessionId,
    channelId: triggerData.channelId,
    cleanMessage: triggerData.cleanMessage || '',
    slotNumber: triggerData.slotNumber,
    botName: triggerData.botName,
    fileCount,
    binaryKeys: keys.join(',')
  },
  binary: fileCount > 0 ? mergedBinary : undefined
}];

