// Re-attach binaries from Merge Files + combine with Load Memory results
const mergeItem = $('Merge Files').first();
const memoryItems = $('Load Memory').all();

// Build conversation history
let conversationHistory = 'Kein bisheriges Gespraech';
if (memoryItems.length > 0 && memoryItems[0].json && Object.keys(memoryItems[0].json).length > 0) {
  const history = memoryItems.reverse().map(i => {
    const j = i.json;
    const role = j.role || j.type || 'unknown';
    const content = j.content || j.message || j.text || JSON.stringify(j);
    return role + ': ' + content;
  }).join('\n');
  if (history.trim()) conversationHistory = history;
}

return [{
  json: {
    ...mergeItem.json,
    conversationHistory
  },
  binary: mergeItem.binary || undefined
}];

